export interface DKInitiateTransactionRequest {
  request_id: string;
  inquiry_id: string;
  transaction_datetime: string;
  source_app: string;
  transaction_amount: string;
  currency: string;
  payment_type: string;
  source_account_name: string;
  source_account_number: string;
  bene_cust_name: string;
  bene_account_number: string;
  bene_bank_code: string;
  narration: string;
}

export interface DKInitiateTransactionResponse {
  response_code: string;
  response_message: string;
  response_description: string;
  response_data?: {
    inquiry_id: string;
    txn_status_id: string;
  };
}

export interface DKTransactionStatusRequest {
  request_id: string;
  transaction_id: string;
  bene_account_number: string;
}

export interface DKTransactionStatusResponse {
  response_code: string;
  response_detail?: string;
  response_message?: string;
  response_description?: string;
  response_data?: {
    meta_info: {
      request_id: string;
      source_app: string;
      contract_number: string;
      srn: string;
      msg_type: string;
    };
    status: {
      status: string;
      status_desc: string;
      txn_ts: string;
      amount: string;
      debit_account: string;
      credit_account: string;
    };
  };
}
